import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom"; // For redirection if not logged in

function ProfilePage() {
    const [userData, setUserData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const history = useHistory();

    useEffect(() => {
        // Check if the user is logged in by checking the token in localStorage
        const token = localStorage.getItem("authToken");
        if (!token) {
            history.push("/login"); // Redirect to login if not logged in
            return;
        }

        // Fetch user data from server
        const fetchData = async () => {
            try {
                // You might want to pass the token in the Authorization header
                const response = await axios.get('http://localhost:3003/user/profile', {
                    headers: {
                        Authorization: `Bearer ${token}`,
                    },
                });

                if (response.status === 200) {
                    setUserData(response.data); // Store the user data from the response
                }
            } catch (err) {
                setError("Failed to fetch profile data.");
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [history]);

    if (loading) return <div>Loading...</div>;

    if (error) return <div>{error}</div>;

    return (
        <div>
            <h2>Profile</h2>
            {userData ? (
                <div>
                    <h3>Welcome, {userData.name}!</h3>
                    <p>Email: {userData.email}</p>
                    {/* Render other user data as needed */}
                </div>
            ) : (
                <p>No user data available.</p>
            )}
        </div>
    );
}

export default ProfilePage;
